&quot;) ## Valores faltantes por variable: print(na_por_variable) ## pais anio tasa_fin ## 0 0 1999 Se identificaron 1.987 datos faltantes, todos concentrados en la columna tasa_fin, correspondientes a países que no reportaron su información en ciertos años. Dado que estas observaciones no aportan información estadística, se eliminan antes de continuar. df_1 &lt;- df_1 %&gt;% filter(complete.cases(.)) df_2 &lt;- df_2 %&gt;% filter(complete.cases(.)) 2.4 Análisis de series de tiempo Una vez limpio el dataset, construimos la serie temporal de la mediana mundial anual de la tasa de finalización primaria femenina para el período 2000–2022. Trabajar con la mediana, en lugar de la media, es más robusto dado que la distribución entre países es asimétrica. Esta serie permite diagnosticar si la variable presenta tendencia, raíz unitaria o estructura autoregresiva, aspectos fundamentales antes de aplicar cualquier modelo de pronóstico. library(tseries) library(forecast) # Construir serie temporal: mediana mundial por año serie_anual &lt;- df_2 %&gt;% group_by(anio) %&gt;% summarise(mediana = median(tasa_fin, na.rm = TRUE), .groups = &quot;drop&quot;) %&gt;% arrange(anio) # Convertir a objeto ts (frecuencia anual) ts_mediana &lt;- ts(serie_anual$mediana, start = 2000, frequency = 1) # Visualizar la serie plot(ts_mediana, main = &quot;Mediana mundial anual de la tasa de finalización primaria femenina&quot;, ylab = &quot;Mediana (%)&quot;, xlab = &quot;Año&quot;, col = &quot;#1F5AA6&quot;, lwd = 2) grid(col = &quot;#DDDDDD&quot;) 2.4.1 Prueba ADF (Augmented Dickey-Fuller) La prueba ADF evalúa la hipótesis nula de que la serie tiene raíz unitaria (es decir, es no estacionaria). Un p-valor inferior a 0,05 permite rechazar esta hipótesis y concluir que la serie es estacionaria, condición deseable para muchos modelos de series de tiempo. library(tseries) # Prueba ADF sobre la serie de medianas anuales adf_resultado &lt;- adf.test(ts_mediana) cat(&quot;=== Prueba Augmented Dickey-Ful